// Level counts for reference
const LEVEL_LABELS = {1:'A1–A2', 2:'A2–B1', 3:'B1–B2'};
const LEVEL_COLORS = {1:'#FFCC00', 2:'#DD0000', 3:'#222'};

function getSentencesForLevel(level) {
  return ALL_SENTENCES.filter(s => getLevel(s.id) === level);
}

/* ═══════════════════════════════════
   SRS ENGINE
   ═══════════════════════════════════ */
const SRS_GAPS = [3,8,20,50,150,400];
function srsGap(lvl){ return SRS_GAPS[Math.min(lvl, SRS_GAPS.length-1)]; }

function pickQueue(sentences, srsData, mode, size, skipList){
  const skips = new Set(skipList||[]);
  const cards = srsData[mode]||{};
  const iter = srsData[mode+'_iter']||0;
  const due=[], fresh=[];
  for(const s of sentences){
    if(skips.has(s.id)) continue;
    const c = cards[s.id];
    if(c){ if(c.dueAt<=iter) due.push({s,c}); }
    else fresh.push(s);
  }
  due.sort((a,b)=>a.c.dueAt-b.c.dueAt);
  return [...due.map(d=>d.s), ...fresh].slice(0,size);
}

function recordAnswer(srsData, mode, id, correct, iter){
  const cards = {...(srsData[mode]||{})};
  const prev = cards[id]||{level:0,totalPlays:0,correctPlays:0};
  const newLvl = correct ? Math.min(prev.level+1, SRS_GAPS.length-1) : 0;
  const gap = srsGap(newLvl);
  cards[id] = {level:newLvl, dueAt:iter+gap+1, totalPlays:(prev.totalPlays||0)+1, correctPlays:(prev.correctPlays||0)+(correct?1:0)};
  return {...srsData, [mode]:cards, [mode+'_iter']:iter+1};
}

/* ═══════════════════════════════════
   STORAGE
   ═══════════════════════════════════ */
const STORE_KEY = 'dh_app_v2';
function loadStore(){ try{ return JSON.parse(localStorage.getItem(STORE_KEY)||'{}'); }catch{ return {}; } }
function saveStore(d){ try{ localStorage.setItem(STORE_KEY, JSON.stringify(d)); }catch{} }
function getUsers(st){ return st.users||{}; }
function setUser(st, name, data){ const n={...st, users:{...(st.users||{}), [name]:data}}; saveStore(n); return n; }

/* ═══════════════════════════════════
   TTS
   ═══════════════════════════════════ */
let voices = [];
function loadVoices(){ voices = window.speechSynthesis.getVoices(); }
if(typeof window!=='undefined'){ window.speechSynthesis.onvoiceschanged=loadVoices; loadVoices(); }

function bestVoice(lang){
  const code = lang.split('-')[0];
  return voices.filter(v=>v.lang.startsWith(code)&&!v.name.includes('eSpeak')&&!v.name.includes('compact'))[0]
    || voices.find(v=>v.lang.startsWith(code)) || null;
}
function speak(text, lang, rate=0.82){
  return new Promise(done=>{
    window.speechSynthesis.cancel();
    const u = new SpeechSynthesisUtterance(text);
    u.lang=lang; u.rate=rate;
    const v=bestVoice(lang); if(v) u.voice=v;
    u.onend=done; u.onerror=done;
    window.speechSynthesis.speak(u);
    setTimeout(done, Math.max(8000, text.length*80));
  });
}
function wait(ms){ return new Promise(r=>setTimeout(r,ms)); }

