// --- Auth Screen ---
function AuthScreen({onLogin, onRegister}){
  const [tab, setTab] = useState('login');
  const [user, setUser2] = useState('');
  const [pass, setPass] = useState('');
  const [err, setErr] = useState('');
  const go = ()=>{ setErr(''); const r = tab==='login'?onLogin(user.trim(),pass):onRegister(user.trim(),pass); if(r) setErr(r); };
  return h('div',{style:S.page},
    h('div',{style:S.authWrap},
      h('div',{style:S.brand}, h(Icon.Flag), h('div',null, h('div',{style:S.brandName},'Deutsch Hören'), h('div',{style:S.brandSub},'German Listening Practice'))),
      h('div',{style:S.flagStripe}),
      h('div',{style:S.tabRow},
        h('button',{style:{...S.tabBtn,...(tab==='login'?S.tabBtnOn:{})},onClick:()=>setTab('login')},'Sign In'),
        h('button',{style:{...S.tabBtn,...(tab==='register'?S.tabBtnOn:{})},onClick:()=>setTab('register')},'Register')),
      h('input',{style:S.inp,placeholder:'Username',value:user,onChange:e=>setUser2(e.target.value),onKeyDown:e=>e.key==='Enter'&&go(),autoCapitalize:'none',autoCorrect:'off',spellCheck:false}),
      h('input',{style:S.inp,placeholder:'Password',type:'password',value:pass,onChange:e=>setPass(e.target.value),onKeyDown:e=>e.key==='Enter'&&go()}),
      err && h('div',{style:S.errBox},err),
      h('button',{style:S.btnPrimary,onClick:go}, tab==='login'?'Sign In':'Create Account'),
      h('div',{style:S.authNote},'Each user has their own profile and progress. Data is stored on this device.')
    )
  );
}

// --- Home Screen ---
function HomeScreen({user, userData, onLogout, onStart, onStats}){
  const srs = userData.srsData||{};
  const skipList = userData.skipList||[];
  const total = ALL_SENTENCES.length;
  const modeStats = m => {
    const cards = srs[m]||{};
    const vals = Object.values(cards);
    return { seen: vals.length, mastered: vals.filter(c=>c.level>=4).length };
  };
  const en2de = modeStats('en_to_de'), de2en = modeStats('de_to_en');
  const l1=getSentencesForLevel(1).length, l2=getSentencesForLevel(2).length, l3=getSentencesForLevel(3).length;
  return h('div',{style:S.page},
    h('div',{style:S.card},
      h('div',{style:S.homeHdr},
        h('div',{style:S.brand}, h(Icon.Flag), h('div',null, h('div',{style:S.brandName},'Deutsch Hören'), h('div',{style:S.brandSub},user.username))),
        h('button',{style:S.ghostSmall,onClick:onLogout},'Sign out')),
      h('div',{style:S.flagStripe}),
      h('div',{style:S.statGrid},
        h(StatBox,{n:total,label:'Total Sentences',color:C.gold}),
        h(StatBox,{n:en2de.seen+de2en.seen,label:'Times Reviewed',color:C.red}),
        h(StatBox,{n:en2de.mastered,label:'Mastered EN→DE',color:'#4ade80'}),
        h(StatBox,{n:de2en.mastered,label:'Mastered DE→EN',color:'#f472b6'})),
      h('div',{style:{display:'flex',gap:6,justifyContent:'center',marginBottom:4}},
        h('span',{style:{fontSize:11,color:C.gold,fontWeight:700}},l1+' A1-A2'),
        h('span',{style:{fontSize:11,color:'#444'}},'·'),
        h('span',{style:{fontSize:11,color:C.red,fontWeight:700}},l2+' A2-B1'),
        h('span',{style:{fontSize:11,color:'#444'}},'·'),
        h('span',{style:{fontSize:11,color:'#aaa',fontWeight:700}},l3+' B1-B2')),
      h('button',{style:S.btnBig,onClick:onStart}, h(Icon.Play), ' Start Listening Session'),
      h('button',{style:S.btnSecondary,onClick:onStats}, h(Icon.Chart), ' View Progress'),
      skipList.length>0 && h('div',{style:{textAlign:'center',color:C.red,fontSize:12,marginTop:4}},'🚫 '+skipList.length+' sentence'+(skipList.length>1?'s':'')+' hidden')
    )
  );
}
function StatBox({n,label,color}){
  return h('div',{style:{...S.statBox,borderColor:color+'44'}},
    h('div',{style:{...S.statN,color}},n),
    h('div',{style:S.statLbl},label));
}

