// --- Session Screen ---
function SessionScreen({cfg, srsData, onSave, onDone, skipList, onSkipAdd}){
  const {level, mode, showBtn, size} = cfg;
  const sentences = getSentencesForLevel(level);
  const srcLang = mode==='en_to_de'?'en-US':'de-DE';
  const tgtLang = mode==='en_to_de'?'de-DE':'en-US';
  const queue = useRef(pickQueue(sentences, srsData, mode, size, skipList));
  const [idx, setIdx] = useState(0);
  const [stage, setStage] = useState('source');
  const [paused, setPaused] = useState(false);
  const [srs, setSrs] = useState(srsData);
  const [done, setDone] = useState(false);
  const [score, setScore] = useState({correct:0,wrong:0});
  const [showText, setShowText] = useState(false);
  const cancelled = useRef(false);
  const pausedRef = useRef(false);
  const skipRef = useRef(false);
  const banRef = useRef(false);
  const answerCb = useRef(null);
  const revealCb = useRef(null);
  const curSentence = useRef(null);
  const srsRef = useRef(srsData);

  async function doWait(ms){
    const chunks = Math.ceil(ms/50);
    for(let i=0;i<chunks;i++){
      if(cancelled.current||skipRef.current||banRef.current) return;
      while(pausedRef.current) await wait(50);
      await wait(50);
    }
  }

  async function playSentence(s){
    skipRef.current=false; banRef.current=false; setShowText(false);
    const src = mode==='en_to_de'?s.en:s.de;
    const tgt = mode==='en_to_de'?s.de:s.en;
    const check = ()=> cancelled.current||skipRef.current||banRef.current;

    if(mode==='de_to_en'){
      setStage('source'); await speak(src,srcLang); if(check()) return check()&&banRef.current?'banned':'skip';
      setStage('gap4'); await doWait(4000); if(check()) return banRef.current?'banned':'skip';
      setStage('source2'); await speak(src,srcLang); if(check()) return banRef.current?'banned':'skip';
      setStage('gap3'); await doWait(3000); if(check()) return banRef.current?'banned':'skip';
      setStage('target1'); await speak(tgt,tgtLang); if(check()) return banRef.current?'banned':'skip';
      if(!showBtn) return 'correct';
      setStage('reveal');
      await new Promise(r=>{revealCb.current=r});
      if(check()) return 'skip';
      setStage('awaiting');
      return new Promise(r=>{answerCb.current=r});
    } else {
      setStage('source'); await speak(src,srcLang); if(check()) return banRef.current?'banned':'skip';
      setStage('gap4'); await doWait(4000); if(check()) return banRef.current?'banned':'skip';
      setStage('target1'); await speak(tgt,tgtLang); if(check()) return banRef.current?'banned':'skip';
      setStage('gap3'); await doWait(3000); if(check()) return banRef.current?'banned':'skip';
      setStage('target2'); await speak(tgt,tgtLang); if(check()) return banRef.current?'banned':'skip';
      setStage('gap2'); await doWait(2000); if(check()) return banRef.current?'banned':'skip';
      setStage('target3'); await speak(tgt,tgtLang); if(check()) return banRef.current?'banned':'skip';
      if(!showBtn) return 'correct';
      setStage('reveal');
      await new Promise(r=>{revealCb.current=r});
      if(check()) return 'skip';
      setStage('awaiting');
      return new Promise(r=>{answerCb.current=r});
    }
  }

  const handleAnswer = correct => { if(answerCb.current){answerCb.current(correct?'correct':'wrong');answerCb.current=null;} };
  const handleRevealDone = correct => { if(revealCb.current){revealCb.current();revealCb.current=null;} if(answerCb.current){answerCb.current(correct?'correct':'wrong');answerCb.current=null;} };
  const handleBan = ()=>{
    const s=curSentence.current; if(!s) return;
    if(onSkipAdd) onSkipAdd(s.id);
    banRef.current=true; skipRef.current=true;
    window.speechSynthesis.cancel();
    if(answerCb.current){answerCb.current('correct');answerCb.current=null;}
    if(revealCb.current){revealCb.current();revealCb.current=null;}
  };

  useEffect(()=>{
    cancelled.current=false;
    let localSrs = {...srsData};
    async function run(){
      const Q = queue.current;
      for(let i=0;i<Q.length&&!cancelled.current;i++){
        setIdx(i);
        curSentence.current=Q[i];
        const iter = localSrs[mode+'_iter']||0;
        const result = await playSentence(Q[i]);
        if(cancelled.current) break;
        if(result==='banned') continue;
        const correct = result!=='wrong';
        localSrs = recordAnswer(localSrs, mode, Q[i].id, correct, iter);
        srsRef.current=localSrs; setSrs({...localSrs});
        setScore(p=>({correct:p.correct+(correct?1:0),wrong:p.wrong+(correct?0:1)}));
        if(!cancelled.current&&!showBtn&&i<Q.length-1){ setStage('gap_between'); await doWait(3000); }
      }
      onSave(localSrs); setDone(true); setStage('done');
      window.speechSynthesis.cancel();
    }
    run();
    return ()=>{ cancelled.current=true; window.speechSynthesis.cancel();
      if(answerCb.current){answerCb.current('correct');answerCb.current=null;}
      if(revealCb.current){revealCb.current();revealCb.current=null;} };
  },[]);

  const togglePause = ()=>{ const p=!pausedRef.current; pausedRef.current=p; setPaused(p); p?window.speechSynthesis.pause():window.speechSynthesis.resume(); };
  const skipSentence = ()=>{ skipRef.current=true; window.speechSynthesis.cancel();
    if(answerCb.current){answerCb.current('correct');answerCb.current=null;}
    if(revealCb.current){revealCb.current();revealCb.current=null;} };
  const goHome = ()=>{ cancelled.current=true; window.speechSynthesis.cancel();
    if(answerCb.current){answerCb.current('correct');answerCb.current=null;}
    if(revealCb.current){revealCb.current();revealCb.current=null;} onDone(); };

  const Q = queue.current;
  const cur = Q[Math.min(idx,Q.length-1)];
  const pct = Q.length?Math.round(idx/Q.length*100):0;
  const stg = STAGES[stage]||STAGES.source;
  const col = stg.color;
  const txt = stg.txt(mode);
  const isAwaiting = stage==='awaiting';
  const isReveal = stage==='reveal';

  if(done){
    const acc = (score.correct+score.wrong)>0?Math.round(score.correct/(score.correct+score.wrong)*100):0;
    return h('div',{style:S.page},h('div',{style:S.card},
      h('div',{style:S.doneIcon},acc>=80?'🎉':acc>=50?'👍':'💪'),
      h('div',{style:S.doneTitle},'Session Complete'),
      h('div',{style:S.flagStripe}),
      h('div',{style:S.doneGrid},
        h('div',{style:S.doneItem},h('span',{style:{...S.doneNum,color:C.gold}},score.correct),h('span',{style:S.doneLbl},'Correct')),
        h('div',{style:S.doneItem},h('span',{style:{...S.doneNum,color:C.red}},score.wrong),h('span',{style:S.doneLbl},'Wrong')),
        h('div',{style:S.doneItem},h('span',{style:{...S.doneNum,color:'#fff'}},acc+'%'),h('span',{style:S.doneLbl},'Score'))),
      !showBtn && h('div',{style:S.autoNote},'Auto-play mode: all sentences marked correct.'),
      h('button',{style:S.btnPrimary,onClick:onDone},'Back to Home')
    ));
  }

  return h('div',{style:S.page},h('div',{style:S.card},
    h('div',{style:S.sessHdr},
      h('div',{style:{...S.modePill,borderColor:col+'55',color:col}}, mode==='en_to_de'?'EN → DE':'DE → EN'),
      h('div',{style:{...S.modePill,borderColor:'#222',color:'#555',fontSize:11}}, LEVEL_LABELS[level]),
      h('div',{style:S.sessCount}, (idx+1)+' / '+Q.length),
      h('button',{style:{background:'none',border:'none',color:'#555',cursor:'pointer',fontSize:13,padding:'4px 8px'},onClick:goHome},'🏠')),
    h('div',{style:S.progWrap},h('div',{style:{...S.progFill,width:pct+'%'}})),
    // Listen zone
    h('div',{style:S.listenZone},
      h('div',{style:{...S.orbRing,borderColor:col+'66',background:col+'0d'}},
        h('div',{style:{...S.orbCore,background:col+'33'}},
          h('span',{style:{fontSize:42,lineHeight:1}}, isReveal?'👁':isAwaiting?'❓':'🎧'))),
      h('div',{style:{...S.stageText,color:col}},txt),
      h('div',{style:S.steps},['source','target1','target2','target3'].map((_,i)=>{
        let active,past;
        if(mode==='de_to_en'){
          active=i===0&&['source','gap4'].includes(stage)||i===1&&['source2','gap3'].includes(stage)||i===2&&stage==='target1'||i===3&&['reveal','awaiting'].includes(stage);
          past=i===0&&!['source','gap4',''].includes(stage)||i===1&&['target1','reveal','awaiting'].includes(stage)||i===2&&['reveal','awaiting'].includes(stage);
        } else {
          active=i===0&&['source','gap4'].includes(stage)||i===1&&['target1','gap3'].includes(stage)||i===2&&['target2','gap2'].includes(stage)||i===3&&['target3','awaiting','reveal'].includes(stage);
          past=i===0&&!['source','gap4',''].includes(stage)||i===1&&['target2','gap2','target3','awaiting','reveal'].includes(stage)||i===2&&['target3','awaiting','reveal'].includes(stage);
        }
        return h('div',{key:i,style:{...S.step,background:active?col:past?'#333':'#1a1a1a'}});
      }))),
    // Reveal + answer
    isReveal && h('div',{style:{display:'flex',flexDirection:'column',alignItems:'center',gap:12,marginTop:4,width:'100%'}},
      showText && cur && h('div',{style:{background:'#1a1230',border:'1px solid #a78bfa55',borderRadius:12,padding:'14px 20px',fontSize:18,fontWeight:700,color:'#e9d5ff',textAlign:'center'}},cur.de),
      !showText && h('button',{style:{width:'100%',background:'#1a1230',color:'#a78bfa',border:'2px solid #a78bfa55',borderRadius:14,padding:'14px',fontSize:15,fontWeight:700,cursor:'pointer'},onClick:()=>setShowText(true)},'👁 Show Text'),
      h('div',{style:{display:'flex',justifyContent:'flex-end',width:'100%'}},
        h('button',{style:{background:'none',border:'1px solid '+C.redDim,borderRadius:8,color:C.red,cursor:'pointer',fontSize:12,padding:'6px 10px',display:'flex',alignItems:'center',gap:5},onClick:handleBan}, h(Icon.Ban),' Don\'t play again')),
      h('div',{style:S.ansRow},
        h('button',{style:S.btnWrong,onClick:()=>handleRevealDone(false)}, h(Icon.X),' Wrong'),
        h('button',{style:S.btnRight,onClick:()=>handleRevealDone(true)}, h(Icon.Check),' Got it!'))),
    isAwaiting && !isReveal && h('div',{style:S.ansRow},
      h('button',{style:S.btnWrong,onClick:()=>handleAnswer(false)}, h(Icon.X),' Wrong'),
      h('button',{style:S.btnRight,onClick:()=>handleAnswer(true)}, h(Icon.Check),' Got it!')),
    !isAwaiting && !isReveal && !done && h('div',{style:S.ctrlRow},
      h('button',{style:{...S.ctrlBtn,color:C.red,borderColor:C.redDim},onClick:handleBan,title:"Don't play again"}, h(Icon.Ban)),
      h('button',{style:S.ctrlBtnMain,onClick:togglePause}, paused?h(Icon.Play):h(Icon.Pause)),
      h('button',{style:S.ctrlBtn,onClick:skipSentence,title:'Skip'}, h(Icon.Skip))),
    paused && h('div',{style:S.pausedLbl},'⏸ Paused — tap play to continue'),
    showBtn && score.correct+score.wrong>0 && h('div',{style:S.scoreTick},
      h('span',{style:{color:C.gold}},'✓ '+score.correct),
      h('span',{style:{color:'#444',margin:'0 8px'}},'|'),
      h('span',{style:{color:C.red}},'✗ '+score.wrong))
  ));
}

// --- Stats Screen ---
function StatsScreen({userData, onBack, onRemove}){
  const srs = userData.srsData||{};
  const total = ALL_SENTENCES.length;
  const modeStats = m => {
    const cards = srs[m]||{};
    const vals = Object.values(cards);
    return { seen:vals.length, totalPlays:vals.reduce((a,c)=>a+(c.totalPlays||0),0),
      accuracy: vals.reduce((a,c)=>a+(c.totalPlays||0),0)?Math.round(vals.reduce((a,c)=>a+(c.correctPlays||0),0)/vals.reduce((a,c)=>a+(c.totalPlays||0),0)*100):0,
      mastered:vals.filter(c=>c.level>=4).length, iter:srs[m+'_iter']||0 };
  };
  const skipIds = userData.skipList||[];
  const skipItems = ALL_SENTENCES.filter(s=>skipIds.includes(s.id));
  return h('div',{style:S.page},h('div',{style:S.card},
    h('button',{style:S.backBtn,onClick:onBack}, h(Icon.Back),' Back'),
    h('h2',{style:S.h2},'Progress'),
    h('div',{style:S.flagStripe}),
    h(ModeBlock,{label:'English → German',stats:modeStats('en_to_de'),color:C.gold,srs,mode:'en_to_de',total}),
    h(ModeBlock,{label:'German → English',stats:modeStats('de_to_en'),color:C.red,srs,mode:'de_to_en',total}),
    h('div',{style:S.srsExplain},
      h('div',{style:S.explainTitle},'📈 How spacing works'),
      h('div',{style:S.explainBody},'Sentences return after a number of other sentences played — not time. Each correct answer pushes it further back (3 → 8 → 20 → 50 → 150). A wrong answer resets to 3. Progress is tracked separately for each direction.')),
    skipItems.length>0 && h('div',{style:{marginTop:14}},
      h('div',{style:{fontSize:13,fontWeight:700,color:C.red,marginBottom:8}},'🚫 Do Not Play ('+skipItems.length+')'),
      skipItems.map(s=>h('div',{key:s.id,style:{background:'#111',border:'1px solid #1e1e1e',borderRadius:10,padding:'12px 14px',display:'flex',alignItems:'center',gap:10,marginBottom:6}},
        h('div',{style:{flex:1,minWidth:0}},
          h('div',{style:{color:'#e0e0e0',fontSize:14,fontWeight:600,marginBottom:3}},s.de),
          h('div',{style:{color:'#555',fontSize:13}},s.en)),
        h('button',{style:{background:'none',border:'1px solid #4ade8044',borderRadius:8,color:'#4ade80',cursor:'pointer',fontSize:12,padding:'6px 10px',whiteSpace:'nowrap'},onClick:()=>onRemove(s.id)},'↩ Restore'))))
  ));
}

function ModeBlock({label,stats,color,srs,mode,total}){
  const cards = srs[mode]||{};
  const dist = [0,0,0,0,0,0];
  dist[0] = total - Object.keys(cards).length;
  Object.values(cards).forEach(c=>{ dist[Math.min(c.level+1,5)]++; });
  const maxD = Math.max(...dist,1);
  const cols = ['#333','#93c5fd','#60a5fa','#3b82f6','#1d4ed8','#4ade80'];
  const labels = ['Unseen','Lv1','Lv2','Lv3','Lv4','Master'];
  return h('div',{style:{...S.modeBlock,borderColor:color+'33'}},
    h('div',{style:{...S.modeLbl,color}},label),
    h('div',{style:S.modeGrid},
      h('div',{style:S.mStat},h('div',{style:{...S.mStatN,color}},stats.seen),h('div',{style:S.mStatLbl},'Seen')),
      h('div',{style:S.mStat},h('div',{style:{...S.mStatN,color}},stats.accuracy+'%'),h('div',{style:S.mStatLbl},'Accuracy')),
      h('div',{style:S.mStat},h('div',{style:{...S.mStatN,color}},stats.mastered),h('div',{style:S.mStatLbl},'Mastered')),
      h('div',{style:S.mStat},h('div',{style:{...S.mStatN,color}},stats.iter),h('div',{style:S.mStatLbl},'Plays'))),
    h('div',{style:S.distRow}, dist.map((v,i)=>
      h('div',{key:i,style:S.distCol},
        h('div',{style:S.distBarWrap},h('div',{style:{...S.distBar,height:Math.round(v/maxD*48)+'px',background:cols[i]}})),
        h('div',{style:S.distN},v),
        h('div',{style:S.distLbl},labels[i]))))
  );
}

/* ═══════════════════════════════════
   APP ROOT
   ═══════════════════════════════════ */
function App(){
  const [store, setStore2] = useState(loadStore());
  const [user, setUser2] = useState(null);
  const [screen, setScreen] = useState('auth');

  const ss = d=>{ saveStore(d); setStore2(d); };
  const login = (u,p)=>{ const users=getUsers(store); if(!users[u]) return 'User not found'; if(users[u].password!==p) return 'Wrong password'; setUser2({username:u}); setScreen('home'); return null; };
  const register = (u,p)=>{ if(!u.trim()) return 'Enter a username'; if(u.length<3) return 'Min 3 characters'; if(!p||p.length<4) return 'Password min 4 chars'; if(getUsers(store)[u]) return 'Username taken'; const s=setUser(store,u,{password:p,srsData:{}}); ss(s); setUser2({username:u}); setScreen('home'); return null; };
  const logout = ()=>{ setUser2(null); setScreen('auth'); };
  const ud = ()=> getUsers(store)[user?.username]||{};
  const saveSrs = d=>{ const u2={...ud(),srsData:d}; const s=setUser(store,user.username,u2); ss(s); };
  const addSkip = id=>{ const u2={...ud(),skipList:[...(ud().skipList||[]),id]}; const s=setUser(store,user.username,u2); ss(s); };
  const rmSkip = id=>{ const u2={...ud(),skipList:(ud().skipList||[]).filter(x=>x!==id)}; const s=setUser(store,user.username,u2); ss(s); };

  if(screen==='auth') return h(AuthScreen,{onLogin:login,onRegister:register});
  if(screen==='home') return h(HomeScreen,{user,userData:ud(),onLogout:logout,onStart:()=>setScreen('setup'),onStats:()=>setScreen('stats')});
  if(screen==='setup') return h(SetupScreen,{onBack:()=>setScreen('home'),onStart:cfg=>setScreen({name:'session',cfg})});
  if(screen==='stats') return h(StatsScreen,{userData:ud(),onBack:()=>setScreen('home'),onRemove:rmSkip});
  if(screen?.name==='session') return h(SessionScreen,{cfg:screen.cfg,srsData:ud().srsData||{},onSave:saveSrs,onDone:()=>setScreen('home'),skipList:ud().skipList||[],onSkipAdd:addSkip});
  return null;
}

// Mount
ReactDOM.createRoot(document.getElementById('root')).render(h(React.StrictMode,null,h(App)));
